import jwt
import json
from typing import Dict, Any, Optional

def decode_jwt(token: str, secret: Optional[str] = None, algorithms: list = ['HS256']) -> Dict[str, Any]:
    """
    Decode and verify JWT token for debugging purposes
    
    Args:
        token (str): JWT token to decode
        secret (str, optional): Secret key for verification
        algorithms (list): List of allowed algorithms
    
    Returns:
        dict: Decoded token contents
    """
    try:
        if secret:
            decoded = jwt.decode(token, secret, algorithms=algorithms, options={"verify_signature": True})
        else:
            decoded = jwt.decode(token, options={"verify_signature": False})
        
        return {
            "decoded": decoded,
            "headers": jwt.get_unverified_header(token),
            "valid": True
        }
    except jwt.ExpiredSignatureError:
        return {"error": "Token has expired", "valid": False}
    except jwt.InvalidTokenError:
        return {"error": "Invalid token", "valid": False}
    except Exception as e:
        return {"error": str(e), "valid": False}

def print_jwt_info(token: str, secret: Optional[str] = None):
    """
    Print formatted JWT information for debugging
    
    Args:
        token (str): JWT token to analyze
        secret (str, optional): Secret key for verification
    """
    result = decode_jwt(token, secret)
    
    print("=== JWT DECODING RESULTS ===")
    print(f"Valid: {result.get('valid', False)}")
    
    if 'error' in result:
        print(f"Error: {result['error']}")
        return
    
    print("\nHeaders:")
    headers = result.get('headers', {})
    for key, value in headers.items():
        print(f"  {key}: {value}")
    
    print("\nPayload:")
    payload = result.get('decoded', {})
    for key, value in payload.items():
        print(f"  {key}: {value}")
    
    print("\n" + "="*30)